@app.cell(hide_code=True)
def _s5_show(TRUE_COLOR, WRONG_COLOR, T, mo, noise_picker, plt, quant_picker):
    _nr = float(noise_picker.value)
    _qb = int(quant_picker.value)
    _key = f"{_nr}|{_qb}"
    if _key not in T.PERTURB_RESULTS:
        # Some keys may serialize as "0|0" vs "0.0|0" depending on Python json
        for k in T.PERTURB_RESULTS:
            kn, kq = k.split("|")
            if float(kn) == _nr and int(kq) == _qb:
                _key = k
                break
    _results = T.PERTURB_RESULTS[_key]

    _all_ok = all(r["correct"] for r in _results)
    _rec_str = "".join(r["recovered_word"] for r in _results)
    _noise_s = f"noise ‖δ‖ = {_nr:.2f}"
    _quant_s = f"{_qb}-bit quant" if _qb else "no quant"

    _fig, _ax = plt.subplots(
        figsize=(max(4.0, len(_results) * 1.5), 3.2),
        constrained_layout=True,
    )
    _labels = [repr(r["true_word"]).strip("'") for r in _results]
    _norms = [r["perturbation_norm"] for r in _results]
    _bcolors = [TRUE_COLOR if r["correct"] else WRONG_COLOR for r in _results]
    _ax.bar(_labels, _norms, color=_bcolors, alpha=0.85)
    _ax.set_xlabel("Token")
    _ax.set_ylabel("Perturbation ‖δ‖")
    _ax.set_title(
        "Per-position perturbation norm  (green = correct, red = wrong)",
        fontsize=10,
    )
    _ax.grid(True, alpha=0.2, axis="y")

    _rows = "\n".join(
        f"| {r['pos']} | `{r['true_word']}` | `{r['recovered_word']}` "
        f"| {r['perturbation_norm']:.4f} | {r['min_loss']:.2e} | "
        f"{'✓' if r['correct'] else '✗'} |"
        for r in _results
    )
    _table = (
        "| Pos | True | Recovered | ‖δ‖ | Min loss | Match |\n"
        "|---|---|---|---:|---:|:---:|\n" + _rows
    )
    _verdict = (
        f"With {_noise_s} and {_quant_s}, recovery of *\"{T.PERTURB_PROMPT}\"* "
        f"**succeeded** at every position and returned **\"{_rec_str}\"**. "
        f"The perturbation stayed below the half-margin threshold at every "
        f"position, exactly as Theorem 3.2 predicts."
        if _all_ok else
        f"With {_noise_s} and {_quant_s}, recovery of *\"{T.PERTURB_PROMPT}\"* "
        f"**failed** and returned **\"{_rec_str}\"**. The perturbation crossed "
        f"the half-margin threshold at the positions plotted in red, and the "
        f"exhaustive search latched onto a near-neighbor token instead."
    )
    mo.vstack([
        mo.center(_fig),
        mo.md(_verdict),
        mo.md(_table),
    ])
    return


# ── § 6  Steganography (extension) ─────────────────────────────────────────────

@app.cell(hide_code=True)
def _s6_header(T, mo):
    _bits_per_pos = 8
    _n_pos = len(T.STEGO_TOKEN_IDS)
    mo.vstack([
        mo.md(
            rf"""
## § 6  &nbsp; Steganographic Channel &nbsp; <span style='color:#5b21b6;font-size:0.65em;background:#ede9fe;padding:2px 8px;border-radius:8px;vertical-align:middle;'>OUR EXTENSION</span>

Reframe the paper. Encoder = GPT-2; decoder = SipIt; round-trip = exact.
**Theorem 3.2's slack is unused channel capacity.** Encode a payload as
$\delta$ with $\|\delta\| < \tfrac{{1}}{{2}}\,\mathrm{{margin}}$, transmit the
noisy state, decode the prompt with SipIt **and** the payload from the residual.
            """.strip()
        ),
        mo.callout(
            mo.md(
                rf"**Construction.** Fix an orthonormal basis $\{{e_1, \ldots, "
                rf"e_{_bits_per_pos}\}}$ in $\mathbb{{R}}^{{{T.HIDDEN_DIM}}}$. "
                rf"Encode each bit as a sign $\sigma_i \in \{{-1, +1\}}$ and "
                rf"form $\delta_{{\mathrm{{pos}}}} = m_{{\mathrm{{pos}}}} "
                rf"\sum_i \sigma_i e_i$ with $m_{{\mathrm{{pos}}}} = 0.9 \cdot "
                rf"\tfrac{{\mathrm{{margin}}_{{\mathrm{{pos}}}}}}{{2\sqrt{_bits_per_pos}}}$. "
                rf"This puts $\|\delta\|$ at exactly 90% of the Thm-3.2 budget. "
                rf"The {_n_pos * _bits_per_pos}-bit payload rides entirely in "
                rf"the **signs** of the projections — so $\|\delta\|$ does *not* "
                rf"depend on payload content. Channel: **{_n_pos * _bits_per_pos} "
                rf"bits** ({_n_pos} ASCII char{'s' if _n_pos != 1 else ''}) "
                rf"per cover prompt *\"{T.STEGO_PROMPT}\"*."
            ),
            kind="info",
        ),
        mo.md(
            "Type a payload below — encoding and decoding are pure numpy at "
            "runtime, no model call required."
        ),
    ], gap=0.4)
    return


@app.cell(hide_code=True)
def _s6_payload_ui(mo):
    payload_input = mo.ui.text(
        value="Hi",
        placeholder="Type a short ASCII string …",
        label="Payload to hide in the hidden state",
        full_width=True,
    )
    payload_input
    return (payload_input,)


@app.cell(hide_code=True)
def _s6_show(DIST_COLOR, T, TRUE_COLOR, mo, np, payload_input, plt):
    """Encode payload as δ inside the Theorem 3.2 budget, decode by projection."""
    _payload = payload_input.value or ""
    _clean   = np.array(T.STEGO_CLEAN_HIDDENS)   # (n_pos, 768)
    _margins = np.array(T.STEGO_HALF_MARGINS)    # (n_pos,)
    _n_pos   = _clean.shape[0]
    _bits_per_pos = 8
    _max_chars = _n_pos                          # 1 ASCII byte per position

    # Truncate / pad payload to the carrier capacity
    _trunc = _payload[:_max_chars]
    _bytes = _trunc.encode("ascii", errors="replace")
    _bytes = _bytes[:_n_pos].ljust(_n_pos, b"\x00")

    # Per-position orthonormal basis (deterministic, seeded)
    _rng = np.random.RandomState(2026)
    _bases = []
    for _ in range(_n_pos):
        _rand = _rng.randn(768, _bits_per_pos)
        _Q, _ = np.linalg.qr(_rand)              # 768 × 8, orthonormal cols
        _bases.append(_Q.T)                       # 8 × 768

    # Encode
    _deltas = np.zeros_like(_clean)
    _delta_norms = np.zeros(_n_pos)
    for _pos in range(_n_pos):
        _byte = _bytes[_pos]
        _bits = np.array([(_byte >> i) & 1 for i in range(7, -1, -1)])
        _signs = 2 * _bits - 1
        _m = (_margins[_pos] / 2) / np.sqrt(_bits_per_pos) * 0.9
        _delta = sum(_signs[i] * _m * _bases[_pos][i] for i in range(_bits_per_pos))
        _deltas[_pos] = _delta
        _delta_norms[_pos] = np.linalg.norm(_delta)

    _perturbed = _clean + _deltas

    # Decode by projecting the residual back onto the basis
    _decoded_bytes = bytearray()
    for _pos in range(_n_pos):
        _residual = _perturbed[_pos] - _clean[_pos]
        _proj = _bases[_pos] @ _residual
        _bits_back = (_proj > 0).astype(int)
        _byte_val = sum(int(_bits_back[i]) << (7 - i) for i in range(_bits_per_pos))
        _decoded_bytes.append(_byte_val)
    _decoded_str = bytes(_decoded_bytes).decode("ascii", errors="replace")

    _bound_ok   = bool((_delta_norms < _margins / 2).all())
    _payload_ok = (
        _decoded_str.rstrip("\x00") == _trunc.rstrip("\x00")
    )

    # ── Figure 1: budget vs payload perturbation, per position ───────────────
    def _draw_budget():
        _fig, _ax = plt.subplots(figsize=(7.5, 3.0), constrained_layout=True)
        _x = np.arange(_n_pos)
        _w = 0.34
        _ax.bar(_x - _w/2, _margins / 2, _w, label="½ margin (Thm 3.2 budget)",
                color=TRUE_COLOR, alpha=0.7, edgecolor="white", linewidth=1.0)
        _ax.bar(_x + _w/2, _delta_norms, _w, label="‖δ‖ used by payload",
                color=DIST_COLOR, alpha=0.85, edgecolor="white", linewidth=1.0)
        _labels = [f"pos {i}  ({T.STEGO_TOKENS[i].strip() or '∅'})"
                   for i in range(_n_pos)]
        _ax.set_xticks(_x)
        _ax.set_xticklabels(_labels)
        _ax.set_ylabel("L2 norm")
        _ax.set_title(
            "Budget check — every blue bar must stay below its green bar",
            fontsize=10.5,
        )
        _ax.legend(loc="upper left", fontsize=9, framealpha=0.95)
        _ax.grid(True, alpha=0.2, axis="y")
        return _fig

    # ── Figure 2: clean vs perturbed hidden state at position 0 ──────────────
    def _draw_carrier():
        _n_show = 96
        _fig, _axes = plt.subplots(
            2, 1, figsize=(11, 3.6), sharex=True, constrained_layout=True,
        )
        _axes[0].plot(_clean[0, :_n_show], color=TRUE_COLOR, linewidth=1.1,
                      label="clean h(\"Hello\")")
        _axes[0].plot(_perturbed[0, :_n_show], color=DIST_COLOR, linewidth=1.1,
                      alpha=0.85, label="perturbed (clean + payload δ)")
        _axes[0].set_ylabel("hidden value")
        _axes[0].legend(loc="upper right", fontsize=9, framealpha=0.95)
        _axes[0].set_title(
            f"Position 0 carrier — first {_n_show} of 768 dimensions",
            fontsize=10.5,
        )
        _axes[0].grid(True, alpha=0.2)

        _axes[1].plot(_deltas[0, :_n_show], color="#8b5cf6", linewidth=1.1,
                      label="payload δ (encoded message)")
        _axes[1].axhline(0, color="#888", linewidth=0.5)
        _axes[1].set_ylabel("δ value")
        _axes[1].set_xlabel("dimension")
        _axes[1].legend(loc="upper right", fontsize=9, framealpha=0.95)
        _axes[1].grid(True, alpha=0.2)
        return _fig

    if not _trunc:
        _display = mo.md(
            "_Type a payload above to encode it as a steganographic perturbation._"
        )
    else:
        _truncate_note = (
            f" (truncated from `{_payload!r}` to {_max_chars} char"
            f"{'s' if _max_chars != 1 else ''} — the {_n_pos}-position "
            f"carrier holds {_n_pos} ASCII bytes)"
            if len(_payload) > _max_chars else ""
        )
        # Per-position budget check, framed as percent of margin used
        _budget_used_pct = 100.0 * _delta_norms / (_margins / 2)
        _total_budget    = float(np.linalg.norm(_margins / 2))
        _total_used      = float(np.linalg.norm(_deltas))

        if _bound_ok and _payload_ok:
            _verdict = (
                f"**Round-trip succeeded.** Payload `{_trunc!r}` was decoded "
                f"as `{_decoded_str.rstrip(chr(0))!r}`. The cover prompt "
                f"*\"{T.STEGO_PROMPT}\"* remains recoverable by SipIt because "
                f"every per-position $\\|\\delta\\|$ stayed strictly below "
                f"the half-margin bound. The receiver gets both the cover "
                f"prompt and the hidden message.\n\n"
                f"Per-position budget used: "
                + " · ".join(
                    f"`pos {i}` = {_budget_used_pct[i]:.1f}% of margin"
                    for i in range(_n_pos)
                )
                + f" (total $\\|\\delta\\|$ = {_total_used:.3f}, "
                f"total budget = {_total_budget:.3f}).\n\n"
                f"_Note that the total norm $\\|\\delta\\|$ does **not** "
                f"depend on the payload content — flipping any bit changes "
                f"only the **direction** of $\\delta$, not its magnitude, "
                f"because the basis is orthonormal. The {_n_pos * _bits_per_pos} "
                f"bits of payload are encoded entirely in the **signs** of "
                f"the projections onto the basis vectors. The channel always "
                f"uses the same energy._"
            )
        else:
            _verdict = (
                f"Round-trip status: bound_ok = `{_bound_ok}`, "
                f"payload_ok = `{_payload_ok}`. Decoded `{_decoded_str!r}`. "
                f"This should not happen for ASCII payloads — please file an issue."
            )
        _display = mo.vstack([
            mo.md(f"**Encoded payload:** `{_trunc!r}`{_truncate_note}"),
            mo.center(_draw_budget()),
            mo.center(_draw_carrier()),
            mo.md(_verdict),
        ])
    _display
    return


# ── Onwards ───────────────────────────────────────────────────────────────────

@app.cell(hide_code=True)
def _takeaways(T, mo, np):
    import math as _math
    _ratios = [
        r["min_rand"] / r["true_loss"]
        for _results in T.LANDSCAPES.values()
        for r in _results
        if r["true_loss"] > 0 and r["min_rand"] > 0
    ]
    _orders_lo = int(_math.floor(_math.log10(min(_ratios))))
    _orders_hi = int(_math.floor(_math.log10(max(_ratios))))
    _all_min_loss = [
        r["min_loss"]
        for prompt_results in T.RECOVERIES.values()
        for r in prompt_results if r["correct"]
    ]
    _med_loss = float(np.median(_all_min_loss))
    _med_exp = int(_math.floor(_math.log10(_med_loss)))

    _table_md = (
        rf"""
| § | Claim | Reference | Strength |
|---|---|---|:---:|
| 1 | Distinct prompts → distinct points in PCA(2) | Thm 2.2 / 2.3 | <span style='color:#92400e;background:#fef3c7;padding:1px 6px;border-radius:6px;font-size:0.85em;'>SUGGESTIVE</span> |
| 2 | True token is unique near-zero minimizer vs {T.DISTRACTOR_SAMPLES} distractors | Lemma 3.1 | <span style='color:#1e3a8a;background:#dbeafe;padding:1px 6px;border-radius:6px;font-size:0.85em;'>SAMPLED</span> |
| 3 | True token is unique minimizer over **all {T.VOCAB_SIZE:,}** | Algorithm 1 | <span style='color:#064e3b;background:#d1fae5;padding:1px 6px;border-radius:6px;font-size:0.85em;'>EXHAUSTIVE</span> |
| 5 | Recovery survives $\|\delta\| < \tfrac{{1}}{{2}}\,\mathrm{{margin}}$ | Thm 3.2 | <span style='color:#1e3a8a;background:#dbeafe;padding:1px 6px;border-radius:6px;font-size:0.85em;'>EMPIRICAL</span> |
| 6 | Same budget carries an ASCII payload | Thm 3.2 (constructive) | <span style='color:#5b21b6;background:#ede9fe;padding:1px 6px;border-radius:6px;font-size:0.85em;'>OUR EXTENSION</span> |
        """.strip()
    )
    _tldr_md = (
        rf"**TL;DR.** The loss-landscape gap is **{_orders_lo}–{_orders_hi} "
        rf"orders of magnitude**, which is what makes exhaustive search viable. "
        rf"Median min MSE across pre-computed recoveries: $\sim 10^{{{_med_exp}}}$. "
        rf"Recovery breaks sharply at the half-margin threshold (§ 5); the "
        rf"leftover budget carries {len(T.STEGO_TOKEN_IDS) * 8} bits of ASCII "
        rf"payload (§ 6)."
    )
    _open_md = (
        rf"**Open questions.** The notebook uses GPT-2 small only — the argument "
        rf"should generalize to contemporary models but hasn't been verified there. "
        rf"Margin scaling across depth is unexplored (we work at layer 12 throughout). "
        rf"The threat model assumed throughout is hidden-state leakage; recovery "
        rf"from logits or sampled output is out of scope and likely much harder."
        rf"\n\n---\n\n"
        rf"Paper: [arXiv:2510.15511](https://arxiv.org/abs/2510.15511) · "
        rf"Nikolaou et al., *Language Models Are Injective and Hence Invertible*, "
        rf"ICLR 2026."
        rf"\n\n*Notebook by Peter Li · Brandon Yee · Jacob Crainic for the alphaXiv × marimo competition.*"
    )
    mo.vstack([
        mo.md("## Onwards"),
        mo.md(_table_md),
        mo.callout(mo.md(_tldr_md), kind="success"),
        mo.md(_open_md),
    ], gap=0.5)
    return


